INSERT INTO users (
    email, nickname, name, auth_type, is_enabled, is_locked, deleted_yn, updated_at
) VALUES (
    #{email}, #{nickname}, #{name}, #{authType}, #{isEnabled}, #{isLocked}, #{deletedYn}, NOW()
)

INSERT INTO credentials (
    user_id, password, updated_at
) VALUES (
    #{userId}, #{password}, NOW()
)

INSERT INTO user_roles (
    user_id, role, used_yn, updated_at
) VALUES (
    #{userId}, #{role}, #{usedYn}, NOW()
)
